import 'package:flutter/material.dart';
import 'screens/splash_screen.dart';

void main() {
  runApp(SocioHubApp());
}

class SocioHubApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: "SocioHub",
      debugShowCheckedModeBanner: false,
      theme: ThemeData(
        primarySwatch: Colors.green,
        useMaterial3: true,
      ),
      home: SplashScreen(),
    );
  }
}

class City {
  final String id;
  final String name;

  City({
    required this.id,
    required this.name,
  });

  // Convert to JSON
  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'name': name,
    };
  }

  // Create from JSON
  factory City.fromJson(Map<String, dynamic> json) {
    return City(
      id: json['id'],
      name: json['name'],
    );
  }
}

class Masjid {
  String id;
  String name;
  String societyId;
  String imamId;
  String fajr;
  String zuhr;
  String asr;
  String maghrib;
  String isha;
  String jummah;
  String status;

  Masjid({
    required this.id,
    required this.name,
    required this.societyId,
    required this.imamId,
    required this.fajr,
    required this.zuhr,
    required this.asr,
    required this.maghrib,
    required this.isha,
    required this.jummah,
    this.status = 'pending',
  });

  factory Masjid.fromJson(Map<String, dynamic> json) {
    return Masjid(
      id: json['id'] ?? '',
      name: json['name'] ?? '',
      societyId: json['society_id'] ?? '',
      imamId: json['imam_id'] ?? '',
      fajr: json['fajr'] ?? '',
      zuhr: json['zuhr'] ?? '',
      asr: json['asr'] ?? '',
      maghrib: json['maghrib'] ?? '',
      isha: json['isha'] ?? '',
      jummah: json['jummah'] ?? '',
      status: json['status'] ?? 'pending',
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'name': name,
      'society_id': societyId,
      'imam_id': imamId,
      'fajr': fajr,
      'zuhr': zuhr,
      'asr': asr,
      'maghrib': maghrib,
      'isha': isha,
      'jummah': jummah,
      'status': status,
    };
  }
}

class Restaurant {
  String id;
  String name;
  String societyId;
  String ownerId;
  String phone;
  String category;
  bool deliveryAvailable;
  String status;

  Restaurant({
    required this.id,
    required this.name,
    required this.societyId,
    required this.ownerId,
    required this.phone,
    required this.category,
    this.deliveryAvailable = false,
    this.status = 'pending',
  });

  factory Restaurant.fromJson(Map<String, dynamic> json) {
    return Restaurant(
      id: json['id'] ?? '',
      name: json['name'] ?? '',
      societyId: json['society_id'] ?? '',
      ownerId: json['owner_id'] ?? '',
      phone: json['phone'] ?? '',
      category: json['category'] ?? '',
      deliveryAvailable: json['delivery_available'] ?? false,
      status: json['status'] ?? 'pending',
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'name': name,
      'society_id': societyId,
      'owner_id': ownerId,
      'phone': phone,
      'category': category,
      'delivery_available': deliveryAvailable,
      'status': status,
    };
  }
}

class Service {
  String id;
  String name;
  String serviceType;
  String societyId;
  String providerId;
  String phone;
  int experience;
  String status;

  Service({
    required this.id,
    required this.name,
    required this.serviceType,
    required this.societyId,
    required this.providerId,
    required this.phone,
    required this.experience,
    this.status = 'pending',
  });

  factory Service.fromJson(Map<String, dynamic> json) {
    return Service(
      id: json['id'] ?? '',
      name: json['name'] ?? '',
      serviceType: json['service_type'] ?? '',
      societyId: json['society_id'] ?? '',
      providerId: json['provider_id'] ?? '',
      phone: json['phone'] ?? '',
      experience: json['experience'] ?? 0,
      status: json['status'] ?? 'pending',
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'name': name,
      'service_type': serviceType,
      'society_id': societyId,
      'provider_id': providerId,
      'phone': phone,
      'experience': experience,
      'status': status,
    };
  }
}

class Society {
  final String societyId;
  final String cityId;
  final String societyName;
  final String? area;
  final String createdBy;
  final String status; // pending, approved, rejected
  final DateTime createdAt;

  Society({
    required this.societyId,
    required this.cityId,
    required this.societyName,
    this.area,
    required this.createdBy,
    required this.status,
    required this.createdAt,
  });

  // Convert to JSON
  Map<String, dynamic> toJson() {
    return {
      'societyId': societyId,
      'cityId': cityId,
      'societyName': societyName,
      'area': area,
      'createdBy': createdBy,
      'status': status,
      'createdAt': createdAt.toIso8601String(),
    };
  }

  // Create from JSON
  factory Society.fromJson(Map<String, dynamic> json) {
    return Society(
      societyId: json['societyId'],
      cityId: json['cityId'],
      societyName: json['societyName'],
      area: json['area'],
      createdBy: json['createdBy'],
      status: json['status'],
      createdAt: DateTime.parse(json['createdAt']),
    );
  }
}

import 'package:flutter/material.dart';

class AddSocietyScreen extends StatefulWidget {
  final String cityName;

  AddSocietyScreen({required this.cityName});

  @override
  _AddSocietyScreenState createState() => _AddSocietyScreenState();
}

class _AddSocietyScreenState extends State<AddSocietyScreen> {
  final TextEditingController societyNameController = TextEditingController();
  final TextEditingController areaController = TextEditingController();
  final GlobalKey<FormState> formKey = GlobalKey<FormState>();

  // Sample existing societies for duplicate checking
  final List<String> existingSocieties = [
    "DHA Phase 6",
    "Bahria Town Karachi",
    "Gulshan-e-Iqbal",
    "North Nazimabad",
  ];

  List<String> suggestions = [];

  void checkDuplicates(String query) {
    setState(() {
      suggestions = existingSocieties
          .where((society) => society.toLowerCase().contains(query.toLowerCase()))
          .toList();
    });
  }

  void addSociety() {
    if (formKey.currentState!.validate()) {
      String societyName = societyNameController.text.trim();

      // Check exact match
      bool exactMatch = existingSocieties.any(
        (society) => society.toLowerCase() == societyName.toLowerCase(),
      );

      if (exactMatch) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: Text("This society already exists. Please select it from the list."),
            backgroundColor: Colors.red,
          ),
        );
        return;
      }

      // If no exact match, show success message
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text("Society request submitted for approval!"),
          backgroundColor: Colors.green,
        ),
      );

      // Clear form
      societyNameController.clear();
      areaController.clear();
      suggestions.clear();

      Future.delayed(Duration(seconds: 2), () {
        Navigator.pop(context);
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text("Add New Society"),
        elevation: 0,
        backgroundColor: Colors.green[700],
      ),
      body: SingleChildScrollView(
        padding: EdgeInsets.all(16),
        child: Form(
          key: formKey,
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              // Header
              Text(
                "Add Your Society",
                style: TextStyle(
                  fontSize: 24,
                  fontWeight: FontWeight.bold,
                  color: Colors.green[800],
                ),
              ),
              SizedBox(height: 10),
              Text(
                "Help us build the database. Your society will be reviewed and approved by admin.",
                style: TextStyle(
                  fontSize: 14,
                  color: Colors.grey[600],
                ),
              ),
              SizedBox(height: 30),

              // City (Read-only)
              Text(
                "City",
                style: TextStyle(fontWeight: FontWeight.bold),
              ),
              SizedBox(height: 8),
              Container(
                padding: EdgeInsets.symmetric(horizontal: 12, vertical: 16),
                decoration: BoxDecoration(
                  border: Border.all(color: Colors.grey[300]!),
                  borderRadius: BorderRadius.circular(8),
                  color: Colors.grey[100],
                ),
                child: Text(
                  widget.cityName,
                  style: TextStyle(fontSize: 16),
                ),
              ),
              SizedBox(height: 20),

              // Society Name
              Text(
                "Society Name",
                style: TextStyle(fontWeight: FontWeight.bold),
              ),
              SizedBox(height: 8),
              TextFormField(
                controller: societyNameController,
                onChanged: checkDuplicates,
                decoration: InputDecoration(
                  hintText: "Enter society name...",
                  border: OutlineInputBorder(
                    borderRadius: BorderRadius.circular(8),
                  ),
                  filled: true,
                  fillColor: Colors.white,
                ),
                validator: (value) {
                  if (value == null || value.isEmpty) {
                    return "Please enter society name";
                  }
                  return null;
                },
              ),
              SizedBox(height: 10),

              // Suggestions
              if (suggestions.isNotEmpty)
                Container(
                  padding: EdgeInsets.all(12),
                  decoration: BoxDecoration(
                    color: Colors.blue[50],
                    borderRadius: BorderRadius.circular(8),
                    border: Border.all(color: Colors.blue[200]!),
                  ),
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Text(
                        "Similar societies found:",
                        style: TextStyle(fontWeight: FontWeight.bold),
                      ),
                      SizedBox(height: 8),
                      ...suggestions
                          .map(
                            (suggestion) => Padding(
                              padding: EdgeInsets.symmetric(vertical: 4),
                              child: Row(
                                children: [
                                  Icon(Icons.check_circle, color: Colors.blue, size: 20),
                                  SizedBox(width: 8),
                                  Text(suggestion),
                                ],
                              ),
                            ),
                          )
                          .toList(),
                    ],
                  ),
                ),
              SizedBox(height: 20),

              // Area/Location
              Text(
                "Area / Location",
                style: TextStyle(fontWeight: FontWeight.bold),
              ),
              SizedBox(height: 8),
              TextFormField(
                controller: areaController,
                decoration: InputDecoration(
                  hintText: "Enter area or location...",
                  border: OutlineInputBorder(
                    borderRadius: BorderRadius.circular(8),
                  ),
                  filled: true,
                  fillColor: Colors.white,
                ),
                validator: (value) {
                  if (value == null || value.isEmpty) {
                    return "Please enter area/location";
                  }
                  return null;
                },
              ),
              SizedBox(height: 30),

              // Info Box
              Container(
                padding: EdgeInsets.all(12),
                decoration: BoxDecoration(
                  color: Colors.green[50],
                  borderRadius: BorderRadius.circular(8),
                  border: Border.all(color: Colors.green[200]!),
                ),
                child: Row(
                  children: [
                    Icon(Icons.info, color: Colors.green),
                    SizedBox(width: 12),
                    Expanded(
                      child: Text(
                        "You will become the first admin of this society after approval.",
                        style: TextStyle(fontSize: 13),
                      ),
                    ),
                  ],
                ),
              ),
              SizedBox(height: 30),

              // Submit Button
              SizedBox(
                width: double.infinity,
                height: 50,
                child: ElevatedButton(
                  onPressed: addSociety,
                  style: ElevatedButton.styleFrom(
                    backgroundColor: Colors.green[700],
                    shape: RoundedRectangleBorder(
                      borderRadius: BorderRadius.circular(8),
                    ),
                  ),
                  child: Text(
                    "Submit for Approval",
                    style: TextStyle(
                      fontSize: 16,
                      fontWeight: FontWeight.bold,
                      color: Colors.white,
                    ),
                  ),
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }
}

import 'package:flutter/material.dart';
import 'society_screen.dart';

class CityScreen extends StatefulWidget {
  @override
  _CityScreenState createState() => _CityScreenState();
}

class _CityScreenState extends State<CityScreen> {
  final List<String> cities = [
    "Karachi",
    "Lahore",
    "Islamabad",
    "Rawalpindi",
    "Hyderabad",
    "Faisalabad",
    "Multan",
    "Peshawar",
    "Quetta",
    "Sialkot",
  ];

  late List<String> filteredCities;
  TextEditingController searchController = TextEditingController();

  @override
  void initState() {
    super.initState();
    filteredCities = cities;
  }

  void filterCities(String query) {
    setState(() {
      if (query.isEmpty) {
        filteredCities = cities;
      } else {
        filteredCities = cities
            .where((city) => city.toLowerCase().contains(query.toLowerCase()))
            .toList();
      }
    });
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text("Select Your City"),
        elevation: 0,
        backgroundColor: Colors.green[700],
      ),
      body: Column(
        children: [
          Padding(
            padding: EdgeInsets.all(16),
            child: TextField(
              controller: searchController,
              onChanged: filterCities,
              decoration: InputDecoration(
                hintText: "Search city...",
                prefixIcon: Icon(Icons.search),
                border: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(10),
                ),
                filled: true,
                fillColor: Colors.grey[100],
              ),
            ),
          ),
          Expanded(
            child: filteredCities.isEmpty
                ? Center(
                    child: Text("No city found"),
                  )
                : ListView.builder(
                    itemCount: filteredCities.length,
                    itemBuilder: (context, index) {
                      return ListTile(
                        leading: Icon(Icons.location_city, color: Colors.green),
                        title: Text(filteredCities[index]),
                        trailing: Icon(Icons.arrow_forward),
                        onTap: () {
                          Navigator.push(
                            context,
                            MaterialPageRoute(
                              builder: (context) => SocietyScreen(
                                cityName: filteredCities[index],
                              ),
                            ),
                          );
                        },
                      );
                    },
                  ),
          ),
        ],
      ),
    );
  }
}

import 'package:flutter/material.dart';
import 'home_screen.dart';
import 'add_society_screen.dart';

class SocietyScreen extends StatefulWidget {
  final String cityName;

  SocietyScreen({required this.cityName});

  @override
  _SocietyScreenState createState() => _SocietyScreenState();
}

class _SocietyScreenState extends State<SocietyScreen> {
  // Sample societies - In real app, this will come from Firebase
  final Map<String, List<String>> societiesByCity = {
    "Karachi": ["DHA Phase 6", "Bahria Town Karachi", "Gulshan-e-Iqbal", "North Nazimabad"],
    "Lahore": ["DHA Phase 5", "Bahria Town Lahore", "Garden Town", "Johar Town"],
    "Islamabad": ["F-7", "F-8", "E-7", "I-8"],
    "Rawalpindi": ["Pindi Bhattian", "Adiala Road", "Rawalpindi Cantonment"],
    "Hyderabad": ["Latifabad", "Gulistan-e-Johar", "Hyderabad Cantonment"],
    "Faisalabad": ["Millat Road", "Race Course Road", "Gulberg"],
    "Multan": ["Cantonment", "Nawab Pur Road"],
    "Peshawar": ["Peshawar Cantonment", "Hayatabad"],
    "Quetta": ["Quetta City", "Satellite Town"],
    "Sialkot": ["City Center", "New City"],
  };

  late List<String> societies;
  late List<String> filteredSocieties;
  TextEditingController searchController = TextEditingController();

  @override
  void initState() {
    super.initState();
    societies = societiesByCity[widget.cityName] ?? [];
    filteredSocieties = societies;
  }

  void filterSocieties(String query) {
    setState(() {
      if (query.isEmpty) {
        filteredSocieties = societies;
      } else {
        filteredSocieties = societies
            .where((society) => society.toLowerCase().contains(query.toLowerCase()))
            .toList();
      }
    });
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text("${widget.cityName} - Societies"),
        elevation: 0,
        backgroundColor: Colors.green[700],
      ),
      body: Column(
        children: [
          // Search Bar
          Padding(
            padding: EdgeInsets.all(16),
            child: TextField(
              controller: searchController,
              onChanged: filterSocieties,
              decoration: InputDecoration(
                hintText: "Search society...",
                prefixIcon: Icon(Icons.search),
                border: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(10),
                ),
                filled: true,
                fillColor: Colors.grey[100],
              ),
            ),
          ),
          // Societies List
          Expanded(
            child: filteredSocieties.isEmpty
                ? Center(
                    child: Column(
                      mainAxisAlignment: MainAxisAlignment.center,
                      children: [
                        Icon(Icons.search_off, size: 50, color: Colors.grey),
                        SizedBox(height: 10),
                        Text("No society found"),
                      ],
                    ),
                  )
                : ListView.builder(
                    itemCount: filteredSocieties.length,
                    itemBuilder: (context, index) {
                      return Card(
                        margin: EdgeInsets.symmetric(horizontal: 12, vertical: 6),
                        child: ListTile(
                          leading: Icon(Icons.home, color: Colors.green),
                          title: Text(filteredSocieties[index]),
                          trailing: Icon(Icons.arrow_forward),
                          onTap: () {
                            Navigator.push(
                              context,
                              MaterialPageRoute(
                                builder: (context) => HomeScreen(
                                  cityName: widget.cityName,
                                  societyName: filteredSocieties[index],
                                ),
                              ),
                            );
                          },
                        ),
                      );
                    },
                  ),
          ),
        ],
      ),
      floatingActionButton: FloatingActionButton(
        onPressed: () {
          Navigator.push(
            context,
            MaterialPageRoute(
              builder: (context) => AddSocietyScreen(cityName: widget.cityName),
            ),
          );
        },
        backgroundColor: Colors.green[700],
        child: Icon(Icons.add),
      ),
    );
  }
}

import 'package:flutter/material.dart';
import 'city_screen.dart';

class SplashScreen extends StatefulWidget {
  @override
  _SplashScreenState createState() => _SplashScreenState();
}

class _SplashScreenState extends State<SplashScreen> {
  @override
  void initState() {
    super.initState();

    Future.delayed(Duration(seconds: 3), () {
      Navigator.pushReplacement(
        context,
        MaterialPageRoute(builder: (context) => CityScreen()),
      );
    });
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      body: Container(
        decoration: BoxDecoration(
          gradient: LinearGradient(
            begin: Alignment.topLeft,
            end: Alignment.bottomRight,
            colors: [Colors.green[700]!, Colors.green[400]!],
          ),
        ),
        child: Center(
          child: Column(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              Icon(Icons.home_work, size: 80, color: Colors.white),
              SizedBox(height: 20),
              Text(
                "SocioHub",
                style: TextStyle(
                  fontSize: 36,
                  fontWeight: FontWeight.bold,
                  color: Colors.white,
                ),
              ),
              SizedBox(height: 10),
              Text(
                "Connect Your Community",
                style: TextStyle(
                  fontSize: 16,
                  color: Colors.white70,
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }
}

